module top_module(
    input [3:0] address,
    input read,
    input clk,
    output reg [7:0] data_out
);parameter ROM_SIZE = 16;

reg [7:0] obf_rom [0:ROM_SIZE-1];

initial begin
    obf_rom[0] = 8'h01;
    obf_rom[1] = 8'h02;
    obf_rom[2] = 8'h03;
    obf_rom[3] = 8'h04;
    obf_rom[4] = 8'h05;
    obf_rom[5] = 8'h06;
    obf_rom[6] = 8'h07;
    obf_rom[7] = 8'h08;
    obf_rom[8] = 8'h09;
    obf_rom[9] = 8'h0A;
    obf_rom[10] = 8'h0B;
    obf_rom[11] = 8'h0C;
    obf_rom[12] = 8'h0D;
    obf_rom[13] = 8'h0E;
    obf_rom[14] = 8'h0F;
    obf_rom[15] = 8'h10;
end

always @(posedge clk) begin
    if (read && address < ROM_SIZE) begin
        data_out <= obf_rom[address];
    end
end

endmodule
